            <input type="range" id="slider-T" min="3" max="15" value="8" step="0.5" style="width: 100%;">
        </div>
    </div>

    <div style="position: relative; width: 100%; padding-top: 50%;"> <canvas id="airy-canvas" style="position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: #e0f7fa; border-radius: 4px; border: 1px solid #b2ebf2;"></canvas>
    </div>
</div>

<script>
(function() {
    const canvas = document.getElementById('airy-canvas');
    const ctx = canvas.getContext('2d');

    // Sliders & Labels
    const valD = document.getElementById('val-d');
    const valH = document.getElementById('val-H');
    const valT = document.getElementById('val-T');

    const sldD = document.getElementById('slider-d');
    const sldH = document.getElementById('slider-H');
    const sldT = document.getElementById('slider-T');

    // Constants
    const g = 9.81;
    let time = 0;
    let lastTime = performance.now();

    function resizeCanvas() {
        const rect = canvas.parentElement.getBoundingClientRect();
        canvas.width = rect.width;
        canvas.height = rect.height;
    }

    window.addEventListener('resize', resizeCanvas);
    resizeCanvas();

    // Physics solver for Wave Number (k) using Newton-Raphson or Iteration
    function getWaveNumber(omega, d) {
        let k = (omega * omega) / g; // Deep water guess
        for(let i=0; i<20; i++) {
            k = (omega * omega) / (g * Math.tanh(k * d));
        }
        return k;
    }

    function draw() {
        const now = performance.now();
        const dt = (now - lastTime) / 1000; // in seconds
        lastTime = now;
        time += dt;

        // Get params
        const d = parseFloat(sldD.value);
        const H = parseFloat(sldH.value);
        const T = parseFloat(sldT.value);

        valD.textContent = d;
        valH.textContent = H;
        valT.textContent = T;

        const omega = 2 * Math.PI / T;
        const k = getWaveNumber(omega, d);
        const amplitude = H / 2;

        // Drawing settings
        const width = canvas.width;
        const height = canvas.height;
        ctx.clearRect(0, 0, width, height);

        // Visual scales
        const pixelsPerMeter = height / (d + H + 10);
        const zeroY = 30 + H * pixelsPerMeter; // Mean water level Y coordinate
        const bottomY = zeroY + d * pixelsPerMeter;

        // Draw Seabed
        ctx.fillStyle = "#c2b280"; // sand color
        ctx.fillRect(0, bottomY, width, height - bottomY);
        ctx.strokeStyle = "#8d6e63";
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, bottomY);
        ctx.lineTo(width, bottomY);
        ctx.stroke();

        // Draw Wave Surface
        ctx.beginPath();
        ctx.moveTo(0, zeroY);
        for(let px = 0; px <= width; px += 5) {
            const mx = px / pixelsPerMeter; // convert screen x to meters
            // surface elevation: zeta = A * cos(kx - wt)
            const zeta = amplitude * Math.cos(k * mx - omega * time);
            ctx.lineTo(px, zeroY - zeta * pixelsPerMeter); // minus because Y goes down
        }
        ctx.lineTo(width, bottomY);
        ctx.lineTo(0, bottomY);
        ctx.fillStyle = "rgba(0, 150, 255, 0.2)";
        ctx.fill();
        ctx.strokeStyle = "#0288d1";
        ctx.lineWidth = 2;
        ctx.stroke();

        // Draw Particles
        // We will place a column of 5 particles at the center of the screen
        const midXPixels = width / 2;
        const midX = midXPixels / pixelsPerMeter;

        // Particle depth fractions (0 = surface, 1 = bottom)
        const fractions = [0, 0.25, 0.5, 0.75, 1.0];

        fractions.forEach(frac => {
            const z = -d * frac;

            // Orbit semi-axes
            const a = amplitude * (Math.cosh(k * (z + d)) / Math.sinh(k * d));
            const b = amplitude * (Math.sinh(k * (z + d)) / Math.sinh(k * d));

            const px0 = midXPixels;
            const py0 = zeroY - z * pixelsPerMeter;

            // Draw theoretical orbit (ellipse)
            ctx.beginPath();
            ctx.ellipse(px0, py0, a * pixelsPerMeter, b * pixelsPerMeter, 0, 0, 2 * Math.PI);
            ctx.strokeStyle = "rgba(0, 0, 0, 0.2)";
            ctx.lineWidth = 1;
            ctx.setLineDash([5, 5]);
            ctx.stroke();
            ctx.setLineDash([]); // reset

            // Current displacement
            const xi = -a * Math.sin(k * midX - omega * time);
            const zeta = b * Math.cos(k * midX - omega * time);

            const pX = px0 + xi * pixelsPerMeter;
            const pY = py0 - zeta * pixelsPerMeter; // minus because canvas Y is down

            // Draw particle
            ctx.beginPath();
            ctx.arc(pX, pY, 6, 0, 2 * Math.PI);
            ctx.fillStyle = "#ff5722"; // prominent orange
            ctx.fill();
            ctx.strokeStyle = "#fff";
            ctx.lineWidth = 2;
            ctx.stroke();
        });

        requestAnimationFrame(draw);
    }

    // Start loop
    draw();
})();
</script>
```

## Ostale valne teorije

Iako je Airyjeva linearna teorija temelj za većinu standardnih hidrodinamičkih proračuna broda na dubokoj vodi, ona postaje neprecizna kada valovi postanu izrazito strmi (velika visina u odnosu na duljinu) ili kada se valovi šire u plitkoj vodi.

Za razliku od idealnih sinusoida, stvarni olujni valovi su asimetrični: imaju oštre, uske i visoke brijegove te plitke, dugačke i zaravnjene dolove. Za precizan opis takvih valova, hidrodinamika koristi **nelinearne valne teorije (e: *non-linear wave theories*)**.

Glavne nelinearne teorije koje se primjenjuju u brodogradnji i odobalnom inženjerstvu su:

- **Stokesove teorije višeg reda (e: *Higher-order Stokes wave theories*):** Matematička proširenja linearne teorije primjenom perturbacijskih metoda. U inženjerskoj praksi najčešće se koriste teorije 2., 3. i 5. reda. Prikladne su za strme valove u dubokoj i prijelaznoj vodi (e: *deep and transitional water*).
- **Knoidalna teorija (e: *Cnoidal wave theory*):** Temelji se na eliptičkim funkcijama (Korteweg-de Vries jednadžba). Primjenjuje se isključivo za valove u plitkoj vodi (e: *shallow water*), gdje Stokesove teorije prestaju vrijediti.
- **Teorija usamljenog vala (e: *Solitary wave theory*):** Predstavlja granični slučaj knoidalne teorije za izrazito plitku vodu, gdje se val sastoji samo od jednog brijega koji se kreće potpuno iznad razine mirnog mora, bez dola (npr. tsunami pri dolasku u obalno područje).
- **Teorija strujne funkcije (e: *Stream function theory*):** Numerički pristup koji je razvio R.G. Dean. Ne oslanja se na analitičke aproksimacije i pokazuje izvrsno podudaranje sa stvarnim, ekstremnim asimetričnim valovima u gotovo svim dubinama.

Odabir ispravne matematičke teorije ključan je korak prije početka bilo kakvog proračuna opterećenja. U tu se svrhu u inženjerskoj praksi standardno koristi dijagram područja primjenjivosti (najpoznatiji je tzv. **Le Méhautéov dijagram**).

Dijagram jasno razgraničava koja je teorija fizikalno najtočnija u ovisnosti o dva bezdimenzionalna parametra:

1. **Parametar plitkosti / relativne dubine vode:** $d / (gT^2)$
2. **Parametar strmine vala:** $H / (gT^2)$

Pored granica pojedinih teorija, ovaj dijagram definira i apsolutnu fizikalnu **granicu loma vala (e: *breaking limit*)**, iznad koje val više ne može postojati u zadanom obliku već se ruši i pretvara u bijelu pjenu.
